+    @Test
+    public void test_any_operators_with_empty_array_literal() {
+        Query query = convert("x != any([])");
+        assertThat(query).hasToString("MatchNoDocsQuery(\"Cannot match unless there is at least one non-null candidate\")");
+
+        query = convert("x = any([])");
+        assertThat(query).hasToString("MatchNoDocsQuery(\"Cannot match unless there is at least one non-null candidate\")");
